import java.io.*;
import java.util.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Sanitize and encode the user input to prevent XSS
        String safeUserName = Encode.forHtml(userName);

        System.out.println("Hello, " + safeUserName + "!");

        // Assume the user input contains malicious script tags
        String maliciousInput = "<script>alert('XSS Attack!')</script>";

        // Sanitize and encode the malicious input before displaying it
        String safeMaliciousInput = Encode.forHtml(maliciousInput);

        System.out.println("User input: " + safeMaliciousInput);

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
